const wh = $('Webhook').first().json;
const body = wh.body || wh;
const dig = s => (s ? String(s).replace(/\D/g,'') : '');
let pay=null;
try { const it=$input.all(); if(it.length && it[0].json && it[0].json.transaction_id){const p=it[0].json; pay={amount:p.amount_cents?Number(p.amount_cents)/100:0,status:'PAID',transaction_id:String(p.transaction_id),paid_at:p.paid_at,method:p.payment_method||'PIX',installments:Number(p.installments)||1,provider:p.provider_name||'credpay'};} } catch(e){}
const companies=body.companies||[]; const contacts=body.contacts||[]; const products=body.products||[];
const co=companies[0]||{}; const ct=contacts[0]||{};
const cnpj=dig(co.cnpj); const isPJ=cnpj.length===14; const taxId=isPJ?cnpj:dig(co.cpf_responsavel);
const customer={ customer_name: co.name||((ct.firstname||'')+' '+(ct.lastname||'')).trim()||'Cliente HubSpot', customer_type:isPJ?'Company':'Individual', customer_group:'Volpi', territory:'Brazil', tax_id:taxId, email_id:ct.email||'', mobile_no:ct.phone||'',
  address:(co.endereco||co.cep)?{ title:co.name||'Cliente', type:'Billing', address_line1:co.endereco||'', address_line2:co.complemento||'', city:co.municipio||'', state:co.uf||co.estado_conselho||'', pincode:dig(co.cep), country:'Brazil', email_id:ct.email||'', phone:ct.phone||'' }:null,
  contact:ct.firstname?{ first_name:ct.firstname, last_name:ct.lastname||'', email:ct.email||'', phone:ct.phone||'' }:null };
const presMap={};
if(co.nome_responsavel_tecnico && co.numero_conselho){ presMap['co']={ cpf:dig(co.cpf_responsavel), full_name:co.nome_responsavel_tecnico, councils:[{council_type:(co.conselho||'CRM').replace(/^\d+\s*-\s*/,'')||'CRM', council_number:String(co.numero_conselho), council_state:co.estado_conselho||co.uf||'', is_primary:1}] }; }
const items=[]; const patients=[]; const fp_patients=[]; const seen={};
for(const p of products){ const ic=p.sku; items.push({item_code:ic,qty:Number(p.quantity)||0,rate:Number(p.price)||0,warehouse:'Produtos Acabados - I'});
  for(const pt of (p.patients||[])){ const cpf=dig(pt.cpf); if(cpf&&!seen[cpf]){seen[cpf]=1; patients.push({cpf,patient_name:pt.nome,mobile:pt.telefone||'',gender:'Outro'});}
    const crm=dig(pt.medico_crm); if(pt.medico_nome&&crm){const mk=crm+'-'+(pt.medico_uf||''); if(!presMap[mk])presMap[mk]={cpf:'',full_name:pt.medico_nome,councils:[{council_type:'CRM',council_number:String(pt.medico_crm),council_state:pt.medico_uf||'',is_primary:1}]};}
    fp_patients.push({patient_cpf:cpf,prescriber_cpf:'',prescriber_council:{council_type:'CRM',council_number:String(pt.medico_crm||''),council_state:pt.medico_uf||''},item_code:ic,qty:Number(pt.quantidade)||0}); } }
return [{ json:{ hubspot:{deal_id:String(body.hubspot_deal_id||''),contact_id:String(ct.hs_object_id||'')}, company:'Injemedpharma', customer, prescribers:Object.values(presMap), patients, items, fp_patients, item_fpb: body.item_fpb||null, fpb_map: body.fpb_map||null, fpb_name: body.fpb_name||null, payment: pay, prescriptions:{count:fp_patients.length,reference:'hubspot deal '+(body.hubspot_deal_id||'')} } }];
